select id, project_id, analysis_task_id, health_score, health_level, deduction_detail, risk_count, high_risk_count, snapshot_time, created_by, created_time, updated_by, updated_time from project_health_snapshot h where h.project_id in
#{projectId}
and h.id = ( select h2.id from project_health_snapshot h2 where h2.project_id = h.project_id order by h2.snapshot_time desc, h2.created_time desc limit 1 )
